// e2e/utils/helpers.ts
export async function waitForCondition(
  predicate: () => Promise<boolean>,
  options: { timeout: number; interval: number }
): Promise<void> {
  const start = Date.now();
  while (Date.now() - start < options.timeout) {
    if (await predicate()) return;
    await sleep(options.interval);
  }
  throw new Error(`Condition not met within ${options.timeout}ms`);
}

export async function waitForAgentState(agentId: string, expectedState: string) {
  return waitForCondition(async () => {
    const resp = await fetch(`${gateway.url}/api/agents/${agentId}`);
    const { state } = await resp.json();
    return state === expectedState;
  }, { timeout: 15000, interval: 500 });
}
